fn solve(weight: Vec<i64>) -> i64 {
    let n = weight.len();
    if n == 0 {
        return 0;
    }
    let mut prev_greater = vec![-1; n];
    let mut stack = Vec::new();
    for i in 0..n {
        while let Some(&top) = stack.last() {
            if weight[top] <= weight[i] {
                stack.pop();
            } else {
                break;
            }
        }
        if let Some(&top) = stack.last() {
            prev_greater[i] = top;
        } else {
            prev_greater[i] = -1;
        }
        stack.push(i);
    }
    let mut dp = vec![0; n];
    for i in 0..n {
        if i == 0 {
            dp[i] = 0;
            continue;
        }
        let p = prev_greater[i];
        if p != -1 {
            let prev_dp = if p == 0 {
                0
            } else {
                dp[p - 1]
            };
            dp[i] = std::cmp::max(dp[i - 1], prev_dp + 1);
        } else {
            dp[i] = dp[i - 1];
        }
    }
    dp[n - 1]
}
